INSERT INTO `achievement_locale` (`ID`, `locale`, `Description_lang`, `Title_lang`, `Reward_lang`, `VerifiedBuild`) VALUES
(62773, 'frFR', 'Accomplir les hauts faits de pêche des abysses listés ci-dessous.', 'Pêche des abysses : rivalité avec Je\’ju', '', 67186),
(61883, 'frFR', 'Ne pas vous faire attraper pendant la première minute d\’un duel de décoration à trois reprises.', 'Insaisissable', '', 67186),
(61887, 'frFR', 'Accomplir tous les hauts faits du duel de décoration.', 'Déguisement à quatre épingles', '', 67186),
(61886, 'frFR', 'Débloquer toutes les améliorations de kit du duel de décoration.', 'Kit ou double', '', 67186),
(61882, 'frFR', 'Réussir à perdre le statut « Personnage révélé » sans se faire attraper en duel de décoration.', 'Entre les mailles du filet', '', 67186),
(61881, 'frFR', 'Être le dernier leurre non attrapé de votre équipe dans un duel de décoration.', 'La cachette parfaite', '', 67186),
(61880, 'frFR', 'Se cacher et éviter de se faire repérer pendant une minute et demie en duel de décoration.', 'Froides sont les ténèbres', '', 67186),
(61879, 'frFR', 'Gagner une partie en tant que limier au cours de laquelle tous les leurres se sont fait attraper en moins de deux minutes en duel de décoration.', 'C\’est toi le chat !', '', 67186),
(61878, 'frFR', 'Réussir à attraper des personnages-joueurs adverses avec un personnage forestier des arcanes en duel de décoration.', 'Qui va à la chasse perd la face', '', 67186),
(61793, 'frFR', 'Réussir à attraper des personnages-joueurs adverses avec un personnage annulateur en duel de décoration.', 'Déploiement dans le Vide', '', 67186),
(61792, 'frFR', 'Réussir à attraper des personnages-joueurs adverses avec un personnage brise-sort en duel de décoration.', 'Bibidi babidi… BOUH !', '', 67186),
(63263, 'frFR', '', '[DNT]Midnight Keystone Myth: Season One Personal Achievement', '', 67186),
(63097, 'frFR', 'Obtenir une cote mythique + d\’au moins 3 400 lors de la saison 1 de Midnight.', 'Saga mythique de Midnight : saison 1', 'Le titre « le belligérant ombreux » ou « la belligérante ombreuse » et l\’objet Selle perdue dans le temps', 67186),
