INSERT INTO `currency_types_locale` (`ID`, `locale`, `Name_lang`, `Description_lang`, `VerifiedBuild`) VALUES
(3513, 'frFR', 'Noyau du Vide nébuleux', 'Des noyaux que vous pouvez transformer en équipement puissant en terrassant des adversaires redoutables dans les raids de la saison 1 de Midnight ou en terminant des donjons en mythique +, des Gouffres abondants et des traques en mode cauchemar.', 67186),
(3347, 'frFR', 'Écu de l\’aube mythique', 'Utilisé pour améliorer l\’équipement mythique dans la saison 1 de Midnight, jusqu\’aux niveaux d\’objet 276-289.\n\nUtilisé en artisanat, fixe le niveau d\’objet à 272-285 selon la qualité.\n\nObtenu grâce aux activités suivantes :\n\n– flèche du Vide, faille du Rêve, marche sur Quel\’Danas (mode mythique) ;\n– donjons de clé mythique (+9 et supérieur).', 67186),
(3346, 'frFR', 'Écu de l\’aube héroïque', 'Utilisé pour améliorer l\’équipement héroïque dans la saison 1 de Midnight, jusqu\’aux niveaux d\’objet 263-276. Obtenu grâce aux activités suivantes :\n\n– flèche du Vide, faille du Rêve, marche sur Quel\’Danas (mode héroïque) ;\n– donjons de clé mythique (+4 à +8) ;\n– Gouffres (niveau 11) ;\n– prime de chasse au trésor (niveau 8+) ;\n– traques (mode cauchemar).', 67186),
(3345, 'frFR', 'Écu de l\’aube héroïque', 'Utilisé pour améliorer l\’équipement héroïque dans la saison 1 de Midnight, jusqu\’aux niveaux d\’objet 263-276.\n\nUtilisé en artisanat, fixe le niveau d\’objet à 259-272 selon la qualité.\n\nObtenu grâce aux activités suivantes :\n\n– flèche du Vide, faille du Rêve, marche sur Quel\’Danas (mode héroïque) ;\n– donjons de clé mythique (+4 à +8) ;\n– Gouffres (niveau 11) ;\n– prime de chasse au trésor (niveau 8+) ;\n– traques (mode cauchemar).', 67186),
(3344, 'frFR', 'Écu de l\’aube de champion', 'Utilisé pour améliorer l\’équipement de champion dans la saison 1 de Midnight, jusqu\’aux niveaux d\’objet 250-263. Obtenu grâce aux activités suivantes :\n\n– évènements en extérieur hebdomadaires ;\n– flèche du Vide, faille du Rêve, marche sur Quel\’Danas (mode normal) ;\n– donjons de saison (mode mythique) ;\n– donjons de clé mythique (+2 à +3) ;\n– Gouffres (niveaux 7 à 10) ;\n– prime de chasse au trésor (niveaux 6 à 7) ;\n– traques (mode cauchemar).', 67186),
(3343, 'frFR', 'Écu de l\’aube de champion', 'Utilisé pour améliorer l\’équipement de champion dans la saison 1 de Midnight, jusqu\’aux niveaux d\’objet 250-263. Obtenu grâce aux activités suivantes :\n\n– évènements en extérieur hebdomadaires ;\n– flèche du Vide, faille du Rêve, marche sur Quel\’Danas (mode normal) ;\n– donjons de saison (mode mythique) ;\n– donjons de clé mythique (+2 à +3) ;\n– Gouffres (niveaux 7 à 10) ;\n– prime de chasse au trésor (niveaux 6 à 7) ;\n– traques (mode cauchemar).', 67186),
(3342, 'frFR', 'Écu de l\’aube de vétéran', 'Utilisé pour améliorer l\’équipement vétéran dans la saison 1 de Midnight, jusqu\’aux niveaux d\’objet 237-250. Obtenu grâce aux activités suivantes :\n\n– évènements en extérieur répétables ;\n– flèche du Vide, faille du Rêve, marche sur Quel\’Danas (mode outil Raids) ;\n– donjons de saison (mode héroïque) ;\n– Gouffres (niveaux 5 à 6) ;\n– prime de chasse au trésor (niveaux 4 à 5) ;\n– traques (mode difficile).', 67186),
(3341, 'frFR', 'Écu de l\’aube de vétéran', 'Utilisé pour améliorer l\’équipement vétéran dans la saison 1 de Midnight, jusqu\’aux niveaux d\’objet 237-250.\n\nUtilisé en artisanat, fixe le niveau d\’objet à 233-246 selon la qualité.\n\nObtenu grâce aux activités suivantes :\n\n– évènements en extérieur répétables ;\n– flèche du Vide, faille du Rêve, marche sur Quel\’Danas (mode outil Raids) ;\n– donjons de saison (mode héroïque) ;\n– Gouffres (niveaux 5 à 6) ;\n– prime de chasse au trésor (niveaux 4 à 5) ;\n– traques (mode difficile).', 67186),
(3418, 'frFR', 'Noyau du Vide nébuleux', 'Des noyaux que vous pouvez transformer en équipement puissant en terrassant des adversaires redoutables dans les raids de la saison 1 de Midnight ou en terminant des donjons en mythique +, des Gouffres abondants et des traques en mode cauchemar.', 67186),
(3391, 'frFR', 'Écu de l\’aube d\’aventure', 'Utilisé pour améliorer l\’équipement d\’aventure dans la saison 1 de Midnight, jusqu\’aux niveaux d\’objet 224-237. Obtenu grâce aux activités suivantes :\n\n– évènements en extérieur répétables ;\n– Gouffres de niveau 4 ;\n– traques (mode normal).', 67186),
(3383, 'frFR', 'Écu de l\’aube d\’aventure', 'Utilisé pour améliorer l\’équipement d\’aventure dans la saison 1 de Midnight, jusqu\’aux niveaux d\’objet 224-237.\n\nUtilisé en artisanat, fixe le niveau d\’objet à 220-233 selon la qualité.\n\nObtenu grâce aux activités suivantes :\n\n– évènements en extérieur répétables ;\n– Gouffres de niveau 4 ;\n– traques (mode normal).', 67186),
(3348, 'frFR', 'Écu de l\’aube mythique', 'Utilisé pour améliorer l\’équipement mythique dans la saison 1 de Midnight, jusqu\’aux niveau d\’objet 276-289. Obtenu grâce aux activités suivantes :\n\n– flèche du Vide, faille du Rêve, marche sur Quel\’Danas (héroïque) ;\n– donjons de clé mythique (+9 et supérieur).', 67186);
