(273307, 'frFR', 'Fraîchement pressée par un entrepreneur ou une entrepreneuse intrépide ! Bourrée de cristaux de sucre… ou de mana ?', '', '', '', 'Fiole de citronnade intrépide', 67186),
(265790, 'frFR', 'Une sacoche contenant 10 écus de l\’aube héroïques et mythiques.', '', '', '', 'Cache d\’écus de l\’aube', 67186),
(246753, 'frFR', '', '', '', '', 'Glorieux amas d\’écus de l\’aube mythiques', 67186),
(255627, 'frFR', '', '', '', '', 'Marteau du gladiateur galactique', 67186),
(266969, 'frFR', '', '', '', '', 'Ensemble : habits de plongée', 67186),
(253582, 'frFR', '', '', '', '', 'Batteur nagedent', 67186);
INSERT INTO `journal_encounter_section_locale` (`ID`, `locale`, `Title_lang`, `BodyText_lang`, `VerifiedBuild`) VALUES
(32672, 'frFR', 'Tank', '$bullet; Le Thésauriseur récupère des ressources dans la pile la plus proche pendant |cFF2959D3|Hspell:1235072|h[Mesures ingénieuses]|h|r.\n$bullet; Les champignons gâtés appliquent l\’effet |cFF2959D3|Hspell:1234846|h[Spores toxiques]|h|r au contact, ce qui évite leur |cFF2959D3|Hspell:1245593|h[Explosion putride]|h|r.\n$bullet; |cFF2959D3|Hspell:1234681|h[Rugissement dévorant]|h|r et |cFF2959D3|Hspell:1235125|h[Beuglement généreux]|h|r infligent d\’importants dégâts à tous les personnages-joueurs.', 67186),
(32669, 'frFR', 'Vue d\’ensemble', 'Le Thésauriseur est prêt à tout pour empêcher le pillage de ses réserves, lançant |cFF2959D3|Hspell:1235072|h[Mesures ingénieuses]|h|r lorsque ses points de vie passent à 90 %, 60 % et 30 %, ce qui renforce l\’une de ses techniques.\n\nÀ 100 points d\’énergie, il jette des |cFF2959D3|Hspell:1234233|h[Fournitures gâtées]|h|r dans toute l\’arène, ce qui fait pousser des champignons gâtés pendant 12 s. Tout contact avec un champignon applique l\’effet |cFF2959D3|Hspell:1234846|h[Spores toxiques]|h|r et entraîne sa destruction, ce qui évite une |cFF2959D3|Hspell:1245593|h[Explosion putride]|h|r.', 67186),
(31527, 'frFR', 'Cargaison interdite', 'Une cargaison censée rester à l\’abri des regards indiscrets. Peut servir à se mettre à couvert.', 67186),
(31282, 'frFR', 'Tank', '$bullet; Kystia rend Mordicus hostile envers les personnages-joueurs grâce à |cFF2959D3|Hspell:1230289|h[Imprégnation illicite]|h|r.\n$bullet; Évitez la |cFF2959D3|Hspell:1253811|h[Vaporisation gangrenée]|h|r de Mordicus.\n$bullet; Interrompez les |cFF2959D3|Hspell:1264095|h[Images miroirs]|h|r de Kystia.', 67186),
(31281, 'frFR', 'Soins', '$bullet; Kystia rend Mordicus hostile envers les personnages-joueurs grâce à |cFF2959D3|Hspell:1230289|h[Imprégnation illicite]|h|r.\n$bullet; Évitez la |cFF2959D3|Hspell:1253811|h[Vaporisation gangrenée]|h|r de Mordicus.\n$bullet; Kystia inflige de lourds dégâts à tous les personnages-joueurs victimes de |cFF2959D3|Hspell:1265412|h[Déstabilisation]|h|r.', 67186),
(31280, 'frFR', 'DPS', '$bullet; Kystia rend Mordicus hostile envers les personnages-joueurs grâce à |cFF2959D3|Hspell:1230289|h[Imprégnation illicite]|h|r.\n$bullet; Évitez la |cFF2959D3|Hspell:1253811|h[Vaporisation gangrenée]|h|r de Mordicus.\n$bullet; Interrompez les |cFF2959D3|Hspell:1264095|h[Images miroirs]|h|r de Kystia.', 67186),
(35862, 'frFR', 'Section 18', '', 67186),
(35353, 'frFR', 'Section 17', '|n\nBy speaking with Lindormi near The Timeways portal or at the end of a Keystone Dungeon, characters with a tank specialization can enable |cFF2959D3|Hspell:1295986|h[Lindormi\'s Glow]|h|r when |cFF2959D3|Hspell:1278156|h[Lindormi\'s Guidance]|h|r is inactive.', 67186),
(34751, 'frFR', 'Section 17', '', 67186),
(34733, 'frFR', 'Ruse de Xal\’atath', 'Xal\’atath trahit les personnages-joueurs et révoque ses pactes. En outre, les morts retirent 15 s au temps restant.', 67186),
(34732, 'frFR', 'Fortifié', 'Les unités adverses normales ont 20 % de points de vie supplémentaires et infligent jusqu\’à un maximum de 20 % de dégâts supplémentaires.', 67186),
(34731, 'frFR', 'Tyrannique', 'Les boss ont 25 % de points de vie supplémentaires. Les dégâts des boss et de leurs serviteurs sont augmentés de 15 % au maximum.', 67186),
(34730, 'frFR', 'Tyrannique et Fortifié', 'Ces affixes renforcent les adversaires dans les donjons de clé mythique. L\’un s\’active au niveau mythique 7 et l\’autre au niveau mythique 10. Change chaque semaine.', 67186),
(34727, 'frFR', 'Marché de Xal\’atath : dévorer', '', 67186),
(34725, 'frFR', 'Marché de Xal\’atath : lié par le Vide', '', 67186),
(34722, 'frFR', 'Marché de Xal\’atath : pulsar', '', 67186),
(34720, 'frFR', 'Niveau mythique 6', '$bullet;|cFF2959D3|Hspell:1284818|h[Soutien de Lindormi]|h|r a été retiré.\n\nLes personnages avec une spécialisation de tank peuvent parler à Lindormi près du portail des Voies temporelles ou à la fin d\’un donjon de clé mythique pour obtenir |cFF2959D3|Hspell:1295986|h[Lueur de Lindormi]|h|r, ce qui continuera de mettre en surbrillance les adversaires.', 67186),
(35809, 'frFR', 'Section 158', '', 67186),
(35491, 'frFR', 'Section 69', '', 67186),
(35490, 'frFR', 'Section 70', '', 67186),
(35489, 'frFR', 'Section 76', '', 67186),
