INSERT INTO `mail_template_locale` (`ID`, `locale`, `Body_lang`, `VerifiedBuild`) VALUES
(659, 'frFR', 'Salutations, acolyte !\n\nAdmirez la GLORIEUSE ABONDANCE qui regorge dans ce domaine, quelle merveille ! Elle déferle, bouillonne et défie toute contrainte !\n\nEn remerciement de votre dévotion envers ma divine personne, vous méritez un petit geste bienveillant. Cette fois-ci, sous la forme d\’abondance pure !\n\nEt sachez-le, aimable acolyte : certaines offrandes, telles que la vitalité fusionnée, apparaîtront désormais chez d\’autres pourvoyeurs et pourvoyeuses. Si vos escapades devaient vous mener aux abords des profondeurs de Zul\’Aman, vous les rencontrerez peut-être.\n\nQue vos récoltes soient exceptionnelles !\n\n– Dundun, Loa d\’abondance', 67186);
