INSERT INTO `trait_definition_locale` (`ID`, `locale`, `OverrideName_lang`, `OverrideSubtext_lang`, `OverrideDescription_lang`, `VerifiedBuild`) VALUES
(137688, 'frFR', 'Fabrication multiple méticuleuse', '', 'Vous développez votre maîtrise des matrices d\’enchantement, ce qui augmente la probabilité de produire des objets supplémentaires lors de la fabrication de consommables ou de la création d\’illusions. De plus, vous bénéficiez de +$ev1 $en1 par point dans cette spécialisation.', 67186),
(137685, 'frFR', '', '', 'La Fabrication multiple permet d\’obtenir jusqu\’à +$ev1 % d\’objets supplémentaires lors de la création de consommables.', 67186),
(137681, 'frFR', '', '', 'La Fabrication multiple permet d\’obtenir jusqu\’à +$ev1 % d\’objets supplémentaires lors de la création de consommables.', 67186),
(133669, 'frFR', '', '', 'Confère +$ev1 $en1 lors de la fabrication d\’alliages.|n|nVous apprend à utiliser des composants de finition lors de la fabrication d\’alliages.', 67186);
